   443→
   444→// Start or continue chat session
   445→router.post('/assistant/chat', authMiddleware, async (req, res) => {
   446→  try {
   447→    const { message, checklist_id } = req.body;
   448→
   449→    // Get or create chat session
   450→    let session = await pool.query(
   451→      `SELECT * FROM onboarding_chats
   452→       WHERE candidate_id = $1 AND checklist_id = $2 AND is_active = true
   453→       ORDER BY session_started DESC LIMIT 1`,
   454→      [req.user.id, checklist_id || null]
   455→    );
   456→
   457→    let sessionId;
   458→    let messages = [];
   459→
   460→    if (session.rows.length === 0) {
   461→      const newSession = await pool.query(
   462→        `INSERT INTO onboarding_chats (candidate_id, checklist_id, messages)
   463→         VALUES ($1, $2, $3)
   464→         RETURNING *`,
   465→        [req.user.id, checklist_id || null, JSON.stringify([])]
   466→      );
   467→      sessionId = newSession.rows[0].id;
   468→    } else {
   469→      sessionId = session.rows[0].id;
   470→      messages = session.rows[0].messages || [];
   471→    }
   472→
   473→    // Get company policies for context
   474→    const policies = await pool.query(
   475→      `SELECT category, title, content
   476→       FROM company_policies
   477→       WHERE is_active = true
   478→       ORDER BY category`
   479→    );
   480→
   481→    // Build context from policies
   482→    const policyContext = policies.rows.map(p =>
   483→      `${p.category}: ${p.title}\n${p.content}`
   484→    ).join('\n\n');
   485→
   486→    // Add user message
   487→    messages.push({
   488→      role: 'user',
   489→      content: message,
   490→      timestamp: new Date().toISOString()
   491→    });
   492→
   493→    // Get AI response
   494→    const aiResponse = await getOnboardingAssistantResponse(
   495→      messages,
   496→      policyContext,
   497→      req.user
   498→    );
   499→
   500→    // Add AI response
   501→    messages.push({
   502→      role: 'assistant',
   503→      content: aiResponse,
   504→      timestamp: new Date().toISOString()
   505→    });
   506→
   507→    // Update session
   508→    await pool.query(
   509→      `UPDATE onboarding_chats
   510→       SET messages = $1, last_activity = NOW()
   511→       WHERE id = $2`,
   512→      [JSON.stringify(messages), sessionId]
   513→    );
   514→
   515→    res.json({ response: aiResponse, session_id: sessionId });
   516→  } catch (err) {
   517→    console.error('Error in assistant chat:', err);
   518→    res.status(500).json({ error: 'Failed to process chat message' });
   519→  }
   520→});
