   578→
   579→// Get onboarding documents for a specific candidate (recruiter view)
   580→router.get('/recruiter/candidate/:candidate_id/documents', authMiddleware, async (req, res) => {
   581→  try {
   582→    // Verify user is a recruiter
   583→    if (!req.user.company_id) {
   584→      return res.status(403).json({ error: 'Only recruiters can view onboarding documents' });
   585→    }
   586→
   587→    // Verify candidate is associated with recruiter's company
   588→    const candidateCheck = await pool.query(
   589→      `SELECT id FROM offers WHERE candidate_id = $1 AND company_id = $2 LIMIT 1`,
   590→      [req.params.candidate_id, req.user.company_id]
   591→    );
   592→
   593→    if (candidateCheck.rows.length === 0) {
   594→      return res.status(403).json({ error: 'Candidate not associated with your company' });
