   746→    async function acceptOffer(offerId) {
   747→      if (!confirm('Accept this job offer?')) return;
   748→      try {
   749→        const res = await fetch(`/api/onboarding/offers/${offerId}/accept`, {
   750→          method: 'POST',
   751→          headers: getAuthHeaders(),
