   456→    async function loadOnboardingDocuments() {
   457→      try {
   458→        const response = await fetch(`${BACKEND_URL}/onboarding/recruiter/summary`, {
   459→          headers: { 'Authorization': `Bearer ${localStorage.getItem('rekrutai_token')}` }
   460→        });
   461→
   462→        if (!response.ok) throw new Error('Failed to load documents');
   463→
   464→        const data = await response.json();
   465→        displayCandidates(data);
   466→      } catch (error) {
   467→        console.error('Error:', error);
   468→        document.getElementById('empty-state').style.display = 'block';
   469→        document.getElementById('candidates-container').innerHTML = '';
   470→      }
   471→    }
   472→
   473→    function displayCandidates(candidates) {
   474→      const container = document.getElementById('candidates-container');
   475→
   476→      if (!candidates || candidates.length === 0) {
   477→        document.getElementById('empty-state').style.display = 'block';
   478→        container.innerHTML = '';
   479→        return;
   480→      }
   481→
   482→      container.innerHTML = candidates.map(candidate => `
   483→        <div class="candidate-card" onclick="viewCandidateDetails(${candidate.candidate_id})">
   484→          <div class="candidate-header">
   485→            <div class="candidate-info">
   486→              <h3>${escapeHtml(candidate.candidate_name)}</h3>
   487→              <div class="candidate-email">${escapeHtml(candidate.candidate_email)}</div>
   488→              ${candidate.job_title ? `<div class="candidate-job">${escapeHtml(candidate.job_title)}</div>` : ''}
   489→            </div>
   490→            <span class="onboarding-status status-${candidate.onboarding_status || 'pending'}">
   491→              ${formatStatus(candidate.onboarding_status)}
   492→            </span>
   493→          </div>
   494→
   495→          <div class="docs-summary">
   496→            <div class="summary-item">
   497→              <strong>${candidate.signed_documents || 0}</strong>
   498→              <span>Signed</span>
   499→            </div>
   500→            <div class="summary-item">
   501→              <strong>${candidate.total_documents || 0}</strong>
   502→              <span>Total</span>
   503→            </div>
   504→          </div>
   505→
   506→          ${candidate.due_date ? `
   507→            <div style="margin-top: 12px; padding-top: 12px; border-top: 1px solid var(--border-color); font-size: 12px; color: var(--text-muted);">
   508→              Due: ${formatDate(candidate.due_date)}
   509→            </div>
   510→          ` : ''}
   511→
   512→          <div style="margin-top: 12px; text-align: right;">
   513→            <a class="view-link" onclick="event.stopPropagation(); viewCandidateDetails(${candidate.candidate_id})">View Details →</a>
   514→          </div>
   515→        </div>
   516→      `).join('');
   517→    }
   518→
   519→    async function viewCandidateDetails(candidateId) {
   520→      currentCandidateId = candidateId;
   521→
   522→      try {
   523→        // Load candidate details and documents
   524→        const response = await fetch(
   525→          `${BACKEND_URL}/onboarding/recruiter/candidate/${candidateId}/documents`,
   526→          { headers: { 'Authorization': `Bearer ${localStorage.getItem('rekrutai_token')}` } }
   527→        );
   528→
   529→        if (!response.ok) throw new Error('Failed to load documents');
   530→
   531→        const documents = await response.json();
   532→        const candidateData = documents[0];
   533→
   534→        // Update modal header
   535→        document.getElementById('modal-candidate-name').textContent = candidateData.candidate_name;
   536→        document.getElementById('modal-candidate-email').textContent = candidateData.candidate_email;
   537→
   538→        // Update details
   539→        document.getElementById('modal-job').textContent = candidateData.job_title || '—';
   540→        document.getElementById('modal-start-date').textContent = candidateData.start_date ? formatDate(candidateData.start_date) : '—';
   541→
   542→        // Display documents
   543→        const docsContainer = document.getElementById('modal-documents');
   544→        if (documents.length === 0) {
   545→          docsContainer.innerHTML = '<p style="color: var(--text-muted);">No documents yet</p>';
   546→        } else {
   547→          docsContainer.innerHTML = documents.map(doc => `
   548→            <div class="doc-item" style="border-left-color: ${doc.signed_at ? '#10b981' : doc.uploaded_at ? '#3b82f6' : '#e5e7eb'};">
   549→              <div class="doc-item-header">
   550→                <span class="doc-item-type">${escapeHtml(doc.document_type)}</span>
   551→                <span class="doc-item-date">${formatDate(doc.created_at)}</span>
   552→              </div>
   553→              <div style="display: flex; align-items: center; justify-content: space-between; margin-top: 8px;">
   554→                <div>
   555→                  ${doc.signed_at ? `
   556→                    <span class="document-status status-signed">✓ Signed ${formatDate(doc.signed_at)}</span>
   557→                  ` : doc.uploaded_at ? `
   558→                    <span class="document-status status-uploaded">✓ Generated</span>
   559→                  ` : `
   560→                    <span class="document-status status-pending-doc">Pending</span>
   561→                  `}
   562→                </div>
   563→                <div style="display: flex; gap: 8px;">
   564→                  ${doc.document_content ? `<a class="view-link" onclick="viewDocContent(${doc.id}, '${escapeHtml(doc.document_type)}')">View Details</a>` : ''}
   565→                  ${doc.document_content ? `<a class="view-link" href="/api/onboarding/recruiter/document/${doc.id}/download" target="_blank" style="color: #10b981;">⬇ Download</a>` : ''}
   566→                  ${doc.document_url ? `<a href="${doc.document_url}" target="_blank" class="view-link">Open File</a>` : ''}
   567→                </div>
   568→              </div>
   569→              ${doc.content_summary ? `<p style="font-size: 12px; color: var(--text-muted); margin-top: 8px;">${escapeHtml(doc.content_summary)}</p>` : ''}
   570→              ${doc.signer_ip ? `<p style="font-size: 11px; color: var(--text-muted); margin-top: 4px;">Audit: IP ${escapeHtml(doc.signer_ip)} | ${formatDate(doc.signed_at)}</p>` : ''}
   571→            </div>
   572→          `).join('');
   573→
   574→          // Store docs for preview
   575→          window._currentDocs = documents;
   576→
   577→          // Show download all button if docs have content
   578→          const hasContent = documents.some(d => d.document_content);
   579→          const dlBtn = document.getElementById('download-all-btn');
   580→          if (dlBtn) dlBtn.style.display = hasContent ? 'inline-block' : 'none';
   581→        }
   582→
   583→        // Show modal
   584→        document.getElementById('modal').classList.add('active');
   585→      } catch (error) {
   586→        console.error('Error:', error);
   587→        alert('Failed to load candidate details');
   588→      }
   589→    }
