   591→    function closeModal() {
   592→      document.getElementById('modal').classList.remove('active');
   593→      currentCandidateId = null;
   594→    }
   595→
   596→    function formatStatus(status) {
   597→      const statuses = {
   598→        'pending': 'Pending',
   599→        'in_progress': 'In Progress',
   600→        'completed': 'Completed'
   601→      };
   602→      return statuses[status] || 'Unknown';
   603→    }
   604→
   605→    function formatDate(dateString) {
   606→      if (!dateString) return '—';
   607→      const date = new Date(dateString);
   608→      return date.toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' });
   609→    }
   610→
   611→    function escapeHtml(text) {
   612→      if (!text) return '';
   613→      const map = {
   614→        '&': '&amp;',
   615→        '<': '&lt;',
   616→        '>': '&gt;',
   617→        '"': '&quot;',
   618→        "'": '&#039;'
   619→      };
   620→      return text.replace(/[&<>"']/g, m => map[m]);
   621→    }
   622→
   623→    function viewDocContent(docId, docType) {
   624→      const doc = (window._currentDocs || []).find(d => d.id === docId);
   625→      if (!doc || !doc.document_content) return;
   626→
   627→      const content = typeof doc.document_content === 'string' ? JSON.parse(doc.document_content) : doc.document_content;
   628→      let bodyHtml = '';
   629→
   630→      if (content.form_type === 'I-9') {
   631→        bodyHtml = `
   632→          <p style="font-weight: 600; text-align: center; margin-bottom: 12px;">Employment Eligibility Verification</p>
   633→          <p><strong>Name:</strong> ${escapeHtml(content.employee_name || '')}</p>
   634→          <p><strong>DOB:</strong> ${content.date_of_birth ? new Date(content.date_of_birth).toLocaleDateString() : ''}</p>
   635→          <p><strong>Address:</strong> ${escapeHtml(content.address || '')}, ${escapeHtml(content.city || '')}, ${escapeHtml(content.state || '')} ${escapeHtml(content.zip || '')}</p>
   636→          <p><strong>SSN:</strong> ${content.ssn_last_four}</p>
   637→          <p><strong>Employer:</strong> ${escapeHtml(content.company || '')}</p>
   638→        `;
   639→      } else if (content.form_type === 'W-4') {
   640→        bodyHtml = `
   641→          <p style="font-weight: 600; text-align: center; margin-bottom: 12px;">W-4 Tax Withholding</p>
   642→          <p><strong>Name:</strong> ${escapeHtml(content.employee_name || '')}</p>
   643→          <p><strong>Address:</strong> ${escapeHtml(content.city_state_zip || '')}</p>
   644→          <p><strong>Filing Status:</strong> ${escapeHtml(content.filing_status || 'Single')}</p>
   645→        `;
   646→      } else if (content.form_type === 'Direct Deposit Authorization') {
   647→        bodyHtml = `
   648→          <p style="font-weight: 600; text-align: center; margin-bottom: 12px;">Direct Deposit</p>
   649→          <p><strong>Name:</strong> ${escapeHtml(content.employee_name || '')}</p>
   650→          <p><strong>Bank:</strong> ${escapeHtml(content.bank_name || '')}</p>
   651→          <p><strong>Account Type:</strong> ${escapeHtml(content.account_type || '')}</p>
   652→        `;
   653→      } else {
   654→        bodyHtml = `<pre style="white-space: pre-wrap; font-size: 12px;">${JSON.stringify(content, null, 2)}</pre>`;
   655→      }
   656→
   657→      if (doc.signed_at) {
   658→        bodyHtml += `<hr style="margin: 12px 0;"><p style="color: #10b981; font-weight: 600;">✓ Signed on ${new Date(doc.signed_at).toLocaleString()}</p>`;
   659→        if (doc.signer_ip) bodyHtml += `<p style="font-size: 11px; color: #888;">IP: ${escapeHtml(doc.signer_ip)}</p>`;
   660→      }
   661→
   662→      const overlay = document.createElement('div');
   663→      overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.5);z-index:2000;display:flex;align-items:center;justify-content:center;';
   664→      overlay.onclick = (e) => { if (e.target === overlay) overlay.remove(); };
   665→      overlay.innerHTML = `
   666→        <div style="background:var(--card-bg);border-radius:12px;max-width:500px;width:90%;padding:24px;max-height:80vh;overflow-y:auto;">
   667→          <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;">
   668→            <h3 style="font-size:16px;font-weight:600;">${escapeHtml(docType)}</h3>
   669→            <button onclick="this.closest('[style*=fixed]').remove()" style="background:none;border:none;font-size:20px;cursor:pointer;color:var(--text-muted);">✕</button>
   670→          </div>
   671→          <div style="font-size:13px;line-height:1.7;">${bodyHtml}</div>
   672→        </div>
   673→      `;
   674→      document.body.appendChild(overlay);
   675→    }
   676→
   677→    function downloadAllDocs() {
   678→      const docs = window._currentDocs || [];
   679→      docs.forEach((doc, i) => {
   680→        if (doc.document_content) {
   681→          setTimeout(() => {
   682→            window.open(`/api/onboarding/recruiter/document/${doc.id}/download`, '_blank');
   683→          }, i * 500);
   684→        }
   685→      });
   686→    }
   687→
   688→    // Modal close on click outside
   689→    document.getElementById('modal').addEventListener('click', (e) => {
   690→      if (e.target.id === 'modal') closeModal();
   691→    });
   692→
   693→    // Initialize
   694→    document.addEventListener('DOMContentLoaded', () => {
   695→      loadOnboardingDocuments();
   696→      setupUserMenu();
   697→    });
   698→  </script>
