// Verify the full onboarding E2E flow works
const APP_URL = process.env.APP_URL || 'https://hireloop-vzvw.polsia.app';

async function run() {
  console.log('=== ONBOARDING E2E VERIFICATION ===\n');
  console.log(`Target: ${APP_URL}\n`);

  // Step 0: Login as candidate
  console.log('--- Step 0: Login as candidate ---');
  let token;
  try {
    const loginRes = await fetch(`${APP_URL}/api/auth/login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email: 'sumanthrangausa@gmail.com', password: 'test123' })
    });
    const loginData = await loginRes.json();
    if (!loginRes.ok || !loginData.token) {
      console.log('  Login failed, trying to register...');
      // Try registering
      const regRes = await fetch(`${APP_URL}/api/auth/register`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name: 'Sumanth Ranga',
          email: 'sumanthrangausa@gmail.com',
          password: 'test123',
          role: 'candidate'
        })
      });
      const regData = await regRes.json();
      token = regData.token;
      if (!token) {
        console.log('  ❌ Cannot authenticate:', JSON.stringify(regData));
        return;
      }
    } else {
      token = loginData.token;
    }
    console.log('  ✅ Logged in as candidate');
  } catch(e) {
    console.log('  ❌ Auth error:', e.message);
    return;
  }

  const headers = {
    'Authorization': `Bearer ${token}`,
    'Content-Type': 'application/json'
  };

  // Step 1: Check wizard progress
  console.log('\n--- Step 1: Check wizard progress ---');
  let progressData;
  try {
    const res = await fetch(`${APP_URL}/api/onboarding/wizard/progress`, { headers });
    progressData = await res.json();
    console.log('  has_onboarding:', progressData.has_onboarding);
    if (progressData.has_onboarding) {
      console.log('  checklist status:', progressData.checklist?.status);
      console.log('  wizard step:', progressData.wizard?.current_step);
      console.log('  wizard status:', progressData.wizard?.wizard_status);
      console.log('  documents count:', progressData.documents?.length);
    } else {
      console.log('  ❌ No onboarding found - needs an accepted offer');
      return;
    }
  } catch(e) {
    console.log('  ❌ Error:', e.message);
    return;
  }

  const checklistId = progressData.checklist.id;

  // Step 2: Save personal info (step 1)
  console.log('\n--- Step 2: Save personal info (wizard step 1) ---');
  try {
    const res = await fetch(`${APP_URL}/api/onboarding/wizard/save-step`, {
      method: 'POST',
      headers,
      body: JSON.stringify({
        checklist_id: checklistId,
        step: 1,
        data: {
          legal_first_name: 'Sumanth',
          legal_middle_name: '',
          legal_last_name: 'Ranga',
          date_of_birth: '1990-05-15',
          ssn: '123456789',
          phone: '(555) 123-4567',
          address_line1: '123 Main St',
          address_line2: 'Apt 4B',
          city: 'San Francisco',
          state: 'CA',
          zip_code: '94102'
        }
      })
    });
    const data = await res.json();
    if (data.success) {
      console.log('  ✅ Step 1 saved, wizard step now:', data.wizard?.current_step);
    } else {
      console.log('  ❌ Failed:', JSON.stringify(data));
      return;
    }
  } catch(e) {
    console.log('  ❌ Error:', e.message);
    return;
  }

  // Step 3: Save emergency contact (step 2)
  console.log('\n--- Step 3: Save emergency contact (wizard step 2) ---');
  try {
    const res = await fetch(`${APP_URL}/api/onboarding/wizard/save-step`, {
      method: 'POST',
      headers,
      body: JSON.stringify({
        checklist_id: checklistId,
        step: 2,
        data: {
          emergency_contact_name: 'Jane Ranga',
          emergency_contact_relationship: 'Spouse',
          emergency_contact_phone: '(555) 987-6543',
          emergency_contact_email: 'jane@example.com'
        }
      })
    });
    const data = await res.json();
    if (data.success) {
      console.log('  ✅ Step 2 saved, wizard step now:', data.wizard?.current_step);
    } else {
      console.log('  ❌ Failed:', JSON.stringify(data));
      return;
    }
  } catch(e) {
    console.log('  ❌ Error:', e.message);
    return;
  }

  // Step 4: Save banking & tax info (step 3)
  console.log('\n--- Step 4: Save banking & tax info (wizard step 3) ---');
  try {
    const res = await fetch(`${APP_URL}/api/onboarding/wizard/save-step`, {
      method: 'POST',
      headers,
      body: JSON.stringify({
        checklist_id: checklistId,
        step: 3,
        data: {
          bank_name: 'Chase',
          routing_number: '021000021',
          account_number: '123456789012',
          account_type: 'checking',
          w4_filing_status: 'single'
        }
      })
    });
    const data = await res.json();
    if (data.success) {
      console.log('  ✅ Step 3 saved, wizard step now:', data.wizard?.current_step);
    } else {
      console.log('  ❌ Failed:', JSON.stringify(data));
      return;
    }
  } catch(e) {
    console.log('  ❌ Error:', e.message);
    return;
  }

  // Step 5: Generate documents
  console.log('\n--- Step 5: Generate documents ---');
  let documents;
  try {
    const res = await fetch(`${APP_URL}/api/onboarding/wizard/generate-documents`, {
      method: 'POST',
      headers,
      body: JSON.stringify({ checklist_id: checklistId })
    });
    const data = await res.json();
    if (data.success) {
      documents = data.documents;
      console.log('  ✅ Generated', documents.length, 'documents:');
      documents.forEach(d => {
        console.log(`    - ${d.document_type} (id: ${d.id}, status: ${d.status}, company_id: ${d.company_id})`);
      });
    } else {
      console.log('  ❌ Failed:', JSON.stringify(data));
      return;
    }
  } catch(e) {
    console.log('  ❌ Error:', e.message);
    return;
  }

  // Step 6: Sign all documents
  console.log('\n--- Step 6: Sign all documents ---');
  try {
    const res = await fetch(`${APP_URL}/api/onboarding/wizard/sign-all`, {
      method: 'POST',
      headers,
      body: JSON.stringify({
        checklist_id: checklistId,
        signature_data: 'data:image/png;base64,TEST_SIGNATURE_DATA'
      })
    });
    const data = await res.json();
    if (data.success) {
      console.log('  ✅ Signed', data.signed_documents?.length, 'documents');
      (data.signed_documents || []).forEach(d => {
        console.log(`    - ${d.document_type}: signed_at=${d.signed_at}, ip=${d.signer_ip}`);
      });
    } else {
      console.log('  ❌ Failed:', JSON.stringify(data));
      return;
    }
  } catch(e) {
    console.log('  ❌ Error:', e.message);
    return;
  }

  // Step 7: Check final wizard state
  console.log('\n--- Step 7: Check final wizard state ---');
  try {
    const res = await fetch(`${APP_URL}/api/onboarding/wizard/progress`, { headers });
    const data = await res.json();
    console.log('  checklist status:', data.checklist?.status);
    console.log('  wizard status:', data.wizard?.wizard_status);
    console.log('  wizard step:', data.wizard?.current_step);
    console.log('  documents count:', data.documents?.length);
    console.log('  all signed:', data.documents?.every(d => d.signed_at));
  } catch(e) {
    console.log('  ❌ Error:', e.message);
  }

  // Step 8: Check recruiter view
  console.log('\n--- Step 8: Check recruiter view ---');
  let recruiterToken;
  try {
    const loginRes = await fetch(`${APP_URL}/api/auth/login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email: 'contact@rekrutai.co', password: 'test123' })
    });
    const loginData = await loginRes.json();
    recruiterToken = loginData.token;

    if (!recruiterToken) {
      console.log('  ⚠️ Recruiter login failed (trying different passwords)');
      // Try another password
      for (const pwd of ['password123', 'Password1!', 'recruiter123']) {
        const res2 = await fetch(`${APP_URL}/api/auth/login`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ email: 'contact@rekrutai.co', password: pwd })
        });
        const data2 = await res2.json();
        if (data2.token) {
          recruiterToken = data2.token;
          break;
        }
      }
    }

    if (recruiterToken) {
      const recHeaders = { 'Authorization': `Bearer ${recruiterToken}`, 'Content-Type': 'application/json' };

      // Check summary
      const summaryRes = await fetch(`${APP_URL}/api/onboarding/recruiter/summary`, { headers: recHeaders });
      const summary = await summaryRes.json();
      console.log('  Recruiter summary:', JSON.stringify(summary, null, 2));

      // Check specific candidate docs
      const docsRes = await fetch(`${APP_URL}/api/onboarding/recruiter/candidate/2/documents`, { headers: recHeaders });
      const docs = await docsRes.json();
      console.log('  Candidate docs visible to recruiter:', docs.length);
      if (docs.length > 0) {
        docs.forEach(d => {
          console.log(`    - ${d.document_type}: status=${d.status}, signed=${d.signed_at ? 'YES' : 'NO'}, has_content=${!!d.document_content}`);
        });
      }
    } else {
      console.log('  ⚠️ Could not login as recruiter - skipping recruiter check');
    }
  } catch(e) {
    console.log('  ⚠️ Recruiter check error:', e.message);
  }

  console.log('\n=== VERIFICATION COMPLETE ===');
}

run().catch(e => console.error('Fatal:', e));

