          <tr><td class="label">City:</td><td>${escapeHtmlServer(content.city || '')}</td></tr>
          <tr><td class="label">State:</td><td>${escapeHtmlServer(content.state || '')}</td></tr>
          <tr><td class="label">ZIP:</td><td>${escapeHtmlServer(content.zip || '')}</td></tr>
